<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); if($_SERVER['REQUEST_METHOD']!=='POST'||!verify_csrf($_POST['csrf_token']??null)) die('Invalid request'); $table=$_POST['table']==='contact_queries'?'contact_queries':'bookings'; $return=$table==='bookings'?'bookings.php':'contacts.php'; $status=post_value('status'); if(!in_array($status,['New','Contacted','Confirmed','Cancelled','Completed'],true)) die('Invalid status'); $st=db()->prepare("UPDATE $table SET status=? WHERE id=?"); $st->execute([$status,(int)$_POST['id']]); redirect($return);
